  case 'blueprint_delete_session': {
    const tmux = safe.sanitizeTmuxName(`bp_${args.session_id.substring(0, 12)}`);
    safe.tmuxKill(tmux);  // Kill running tmux session
    const projectPath = safe.resolveProjectPath(args.project);
